#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

struct Node{
    int son[26],fail,len,sz;
}tr[N];

int n,tot;
char s[N];
vector<int> e[N];
long long ans;

void dfs(int x){
    for(int y:e[x]){
        dfs(y);
        tr[x].sz+=tr[y].sz;
    }
    //printf("%d %d %d\n",x,tr[x].sz,tr[x].len);
    ans=max(ans,1ll*tr[x].sz*tr[x].len);
}

int main(){
    scanf("%s",s+1);
    n=strlen(s+1);
    tr[1].len=-1;
    tr[2].len=0;
    tr[2].fail=1;
    e[1].push_back(2);
    tot=2;
    for(int i=1,p=2;i<=n;i++){
        while(s[i]!=s[i-tr[p].len-1])
            p=tr[p].fail;
        if(!tr[p].son[s[i]-'a']){
            tr[p].son[s[i]-'a']=++tot;
            tr[tot].len=tr[p].len+2;
            int u=tr[p].fail;
            while(u && s[i]!=s[i-tr[u].len-1]) u=tr[u].fail;
            if(!u) tr[tot].fail=2;
            else tr[tot].fail=tr[u].son[s[i]-'a'];
            e[tr[tot].fail].push_back(tot);
        }
        p=tr[p].son[s[i]-'a'];
        tr[p].sz++;
        //printf("%d ",tr[p].fail);
    }
    //puts("");
    dfs(1);
    printf("%lld",ans);
    return 0;
}
